// =============================================================================
// Per-file archive fallback
// =============================================================================

/// Outcome of running [`verify_attestation_blob`] against one regular file inside an
/// extracted archive. Captured so [`aggregate_archive_member_outcomes`] can apply the
/// "every member must verify" policy in a separately-testable pure function.
#[derive(Debug, Clone, PartialEq, Eq)]
enum ArchiveMemberOutcome {
    /// The file had at least one attestation and it cryptographically verified.
    Verified,
    /// The file had at least one attestation but verification failed (signature,
    /// certificate chain, workflow mismatch, etc.). Hard failure.
    Failed(String),
    /// The GitHub API returned no attestations for this file's digest.
    NoAttestation,
}

/// Verify a GitHub artifact attestation against each regular file inside an archive.
///
/// Triggered only by [`verify_attestation`] after archive-level verification reports
/// [`AttestationError::NoAttestations`]. Extraction uses mise's standard
/// [`crate::file::untar`] so the supported formats and decompression logic match the
/// install path exactly.
///
/// Returns:
/// - `Ok(true)` when every regular file inside the archive verifies.
/// - [`AttestationError::NoAttestations`] when no inner file has any attestation at all
///   (so callers can fall through to SLSA / checksum verification, exactly as they
///   would have without the fallback).
/// - A `Verification` error in every other case — including partial coverage, where
///   some members verified but others did not. Partial coverage is the smuggling signal
///   and must fail closed.
/// - [`AttestationError::NoAttestations`] when `artifact_path` isn't a recognized
///   archive format. The fallback simply doesn't apply.
async fn verify_attestation_via_archive_contents(
    artifact_path: &Path,
    owner: &str,
    repo: &str,
    expected_workflow: Option<&str>,
    api_url: Option<&str>,
) -> AttestationResult<bool> {
    let Some(format) = archive_format_for_path(artifact_path) else {
        // Not an archive — the fallback does not apply. Surface NoAttestations so the
        // caller's existing fall-through (to SLSA, checksums, etc.) still works.
        debug!(
            "attestation fallback skipped: {} is not a recognized archive format",
            artifact_path.display()
        );
        return Err(AttestationError::NoAttestations);
    };

    let tmp = tempfile::tempdir().map_err(AttestationError::Io)?;
    // strip_components=0: we need the verbatim archive layout so each member's digest
    // matches what the publisher signed. Stripping would change digests and silently
    // break verification.
    let opts = TarOptions {
        strip_components: 0,
        ..TarOptions::new(format)
    };
    crate::file::untar(artifact_path, tmp.path(), &opts)?;

    let members = list_regular_files(tmp.path())?;
    if members.is_empty() {
        return Err(AttestationError::Verification(
            "attestation fallback extracted the archive but found no regular files".to_string(),
        ));
    }

    debug!(
        "attestation fallback: verifying {} regular file(s) extracted from {}",
        members.len(),
        artifact_path.display()
    );

    let root = tmp.path();
    let mut outcomes: Vec<(String, ArchiveMemberOutcome)> =
        Vec::with_capacity(members.len());
    for member in &members {
        let display = member
            .strip_prefix(root)
            .map(|p| p.display().to_string())
            .unwrap_or_else(|_| member.display().to_string());
        let outcome = match verify_attestation_blob(
            member,
            owner,
            repo,
            expected_workflow,
            api_url,
        )
        .await
        {
            Ok(true) => ArchiveMemberOutcome::Verified,
            Ok(false) => ArchiveMemberOutcome::Failed(
                "attestation existed but verification returned false".to_string(),
            ),
            Err(AttestationError::NoAttestations) => ArchiveMemberOutcome::NoAttestation,
            Err(e) => ArchiveMemberOutcome::Failed(e.to_string()),
        };
        outcomes.push((display, outcome));
    }

    let result = aggregate_archive_member_outcomes(outcomes);
    match &result {
        Ok(true) => debug!(
            "attestation fallback succeeded: every member of {} verified",
            artifact_path.display()
        ),
        Err(AttestationError::NoAttestations) => debug!(
            "attestation fallback found no attestations for any member of {}",
            artifact_path.display()
        ),
        Err(e) => debug!(
            "attestation fallback failed for {}: {e}",
            artifact_path.display()
        ),
    }
    result
}

/// Apply the per-file fallback's verification policy to the outcomes collected for each
/// archive member.
///
/// **Policy (fail-closed):**
/// - If every member verified → [`Ok`]`(true)`.
/// - If no member had any attestation → [`AttestationError::NoAttestations`]. This lets
///   callers fall through to other mechanisms (SLSA, checksums).
/// - Otherwise → [`AttestationError::Verification`]. Partial coverage — some members
///   verified but others had no attestation or failed verification — is treated as a
///   hard failure. The publisher either forgot to attest one of their files (in which
///   case failing surfaces the gap) or an attacker is smuggling an unattested file in
///   alongside attested ones. There is no third option, and we cannot tell them apart
///   at verification time, so we reject.
///
/// Factored out of [`verify_attestation_via_archive_contents`] so the policy is unit-
/// testable without touching the filesystem or the GitHub API. Any change to the policy
/// here changes the security boundary of the fallback — the tests below pin it.
fn aggregate_archive_member_outcomes(
    outcomes: Vec<(String, ArchiveMemberOutcome)>,
) -> AttestationResult<bool> {
    if outcomes.is_empty() {
        return Err(AttestationError::Verification(
            "attestation fallback was given no archive members to evaluate".to_string(),
        ));
    }
    if outcomes
        .iter()
        .all(|(_, o)| matches!(o, ArchiveMemberOutcome::Verified))
    {
        return Ok(true);
    }
    if outcomes
        .iter()
        .all(|(_, o)| matches!(o, ArchiveMemberOutcome::NoAttestation))
    {
        return Err(AttestationError::NoAttestations);
    }
    // Mixed: at least one member didn't verify. Build a detailed error naming every
    // unverified member so users (and downstream tooling) can see exactly which file
    // broke the chain.
    let total = outcomes.len();
    let mut failures: Vec<String> = Vec::new();
    for (name, outcome) in &outcomes {
        match outcome {
            ArchiveMemberOutcome::Verified => {}
            ArchiveMemberOutcome::NoAttestation => {
                failures.push(format!("{name}: no GitHub attestation"));
            }
            ArchiveMemberOutcome::Failed(msg) => {
                failures.push(format!("{name}: {msg}"));
            }
        }
    }
    Err(AttestationError::Verification(format!(
        "per-file attestation verification failed for {}/{} archive member(s); \
         every regular file inside the archive must carry a valid GitHub attestation: {}",
        failures.len(),
        total,
        failures.join("; ")
    )))
}

/// Determine the archive format for an arbitrary path, returning `None` for non-archives.
///
/// Wraps [`TarFormat::from_file_name`] with the [`TarFormat::is_archive`] check so the
/// fallback can short-circuit cleanly on raw binaries, single-file `.gz`/`.xz`/etc.
/// compressions, and unknown extensions.
fn archive_format_for_path(path: &Path) -> Option<TarFormat> {
    let file_name = path.file_name()?.to_string_lossy();
    let format = TarFormat::from_file_name(&file_name);
    if format.is_archive() {
        Some(format)
    } else {
        None
    }
}

/// List every regular file under `root`, returning absolute paths.
///
/// Uses [`std::fs::symlink_metadata`] at every step so symlinks are never followed — an
/// archive that bundles a symlink pointing outside its tree (or into a loop) cannot
/// trick this walk into reading foreign files or recursing forever. Symlinks, fifos,
/// sockets, block/char devices, and directories are skipped; only regular files can
/// carry attestations. Hidden files are *not* skipped — the "every regular file"
/// policy is strict by design.
fn list_regular_files(root: &Path) -> std::io::Result<Vec<PathBuf>> {
    let mut out: Vec<PathBuf> = Vec::new();
    let mut stack: Vec<PathBuf> = vec![root.to_path_buf()];
    while let Some(dir) = stack.pop() {
        let entries = match std::fs::read_dir(&dir) {
            Ok(e) => e,
            Err(e) if e.kind() == std::io::ErrorKind::NotFound => continue,
            Err(e) => return Err(e),
        };
        for entry in entries {
            let entry = entry?;
            let path = entry.path();
            // symlink_metadata: never follow symlinks. A symlink to /etc/passwd or to
            // a sibling must not leak bytes from outside the archive into the digest
            // check, nor cause infinite recursion on a loop.
            let metadata = std::fs::symlink_metadata(&path)?;
            if metadata.is_dir() {
                stack.push(path);
            } else if metadata.is_file() {
                out.push(path);
            }
            // else: symlink / fifo / socket / device — skip.
        }
    }
    out.sort();
    Ok(out)
}

