    #[test]
    fn test_resolve_token_wrapper_uses_github_tokens_toml_source() {
        // Proves the wrapper delegates all the way through `resolve_token` to the
        // non-env-var sources — here, the `github_tokens.toml` path (source #4). Without
        // this, a future regression could short-circuit on env vars and silently pass all
        // prior tests.
        let _lock = crate::github::TEST_ENV_LOCK.lock().unwrap();
        let _env = TokenEnvGuard::new();
        let _tokens_file = TokensFileOverrideGuard::set("github.com", "ghp_from_tokens_file");

        let resolved = resolve_token_for_wrapper(None);
        assert_eq!(
            resolved.as_deref(),
            Some("ghp_from_tokens_file"),
            "wrapper should resolve tokens from github_tokens.toml when env vars are empty"
        );
    }

    // ==========================================================================
    // Per-file archive fallback — policy aggregation
    //
    // These tests pin the security boundary of the fallback. The fallback's whole
    // job is to reject archives that contain a single unattested file. Any change to
    // `aggregate_archive_member_outcomes` that loosens one of these cases is a
    // security regression and must be flagged for review.
    // ==========================================================================

    #[test]
    fn aggregate_all_verified_returns_ok_true() {
        let outcomes = vec![
            ("bin/tool".to_string(), ArchiveMemberOutcome::Verified),
            ("lib/libfoo.so".to_string(), ArchiveMemberOutcome::Verified),
            ("LICENSE".to_string(), ArchiveMemberOutcome::Verified),
        ];
        assert_eq!(
            aggregate_archive_member_outcomes(outcomes).unwrap(),
            true,
            "all-verified is the only case that should accept the archive"
        );
    }

    #[test]
    fn aggregate_single_verified_member_returns_ok_true() {
        // Single-file archives still go through the fallback if the outer archive blob
        // had no attestation. One verified member must pass.
        let outcomes = vec![["bin/tool".to_string(), ArchiveMemberOutcome::Verified]];
        assert!(aggregate_archive_member_outcomes(outcomes).unwrap());
    }

    #[test]
    fn aggregate_empty_returns_verification_error() {
        // Empty input means the orchestration loop never ran. Treat as a hard failure
        // rather than vacuously Ok(true) — there is nothing to verify, so "every member
        // verified" cannot be established.
        let err = aggregate_archive_member_outcomes(vec![]).unwrap_err();
        assert!(
            matches!(err, AttestationError::Verification(_)),
            "empty outcomes must hard-fail, got {err:?}"
        );
    }

    #[test]
    fn aggregate_all_no_attestation_returns_no_attestations() {
        // No member had any attestation. This is the only "soft" path — surface
        // NoAttestations so callers fall through to SLSA / checksums, exactly as they
        // would have without the fallback. Anything stricter would mask legitimate
        // "this release simply has no GitHub attestations" cases.
        let outcomes = vec![
            ("bin/tool".to_string(), ArchiveMemberOutcome::NoAttestation),
            ("README".to_string(), ArchiveMemberOutcome::NoAttestation),
        ];
        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
        assert!(
            matches!(err, AttestationError::NoAttestations),
            "all-unattested must be NoAttestations for fall-through, got {err:?}"
        );
    }

    #[test]
    fn aggregate_mixed_verified_and_no_attestation_is_hard_failure() {
        // The smuggling case. The publisher attested `bin/tool` but not `README` —
        // either they forgot (gap) or an attacker slipped `README` past them. We can't
        // tell which, so the archive must be rejected. This is the load-bearing test
        // for "do not guess toward permissiveness".
        let outcomes = vec![
            ("bin/tool".to_string(), ArchiveMemberOutcome::Verified),
            ("README".to_string(), ArchiveMemberOutcome::NoAttestation),
        ];
        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
        match err {
            AttestationError::Verification(msg) => {
                assert!(
                    msg.contains("README"),
                    "error must name the unverified member, got: {msg}"
                );
                assert!(
                    msg.contains("1/2"),
                    "error must report the failure count, got: {msg}"
                );
                assert!(
                    msg.contains("no GitHub attestation"),
                    "error must distinguish no-attestation from failed, got: {msg}"
                );
            }
            other => panic!("mixed verified/unattested must be Verification, got {other:?}"),
        }
    }

    #[test]
    fn aggregate_mixed_verified_and_failed_is_hard_failure() {
        // A member with an attestation that failed verification (signature mismatch,
        // bad chain, etc.) alongside a verified member. Must reject.
        let outcomes = vec![
            ("bin/tool".to_string(), ArchiveMemberOutcome::Verified),
            (
                "lib/libevil.so".to_string(),
                ArchiveMemberOutcome::Failed("signature mismatch".to_string()),
            ),
        ];
        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
        match err {
            AttestationError::Verification(msg) => {
                assert!(
                    msg.contains("lib/libevil.so"),
                    "error must name the failed member, got: {msg}"
                );
                assert!(
                    msg.contains("signature mismatch"),
                    "error must preserve the underlying failure reason, got: {msg}"
                );
            }
            other => panic!("mixed verified/failed must be Verification, got {other:?}"),
        }
    }

    #[test]
    fn aggregate_all_failed_is_hard_failure() {
        let outcomes = vec![
            (
                "a".to_string(),
                ArchiveMemberOutcome::Failed("boom".to_string()),
            ),
            (
                "b".to_string(),
                ArchiveMemberOutcome::Failed("crash".to_string()),
            ),
        ];
        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
        assert!(
            matches!(err, AttestationError::Verification(_)),
            "all-failed must be Verification, got {err:?}"
        );
    }

    #[test]
    fn aggregate_failure_message_lists_every_unverified_member() {
        // 3 members: one verified, two unverified. The error must enumerate both
        // unverified ones (no truncation) so users can see exactly which files broke
        // the chain. Hiding a member behind "and N more" would mask smuggling.
        let outcomes = vec![
            ("ok".to_string(), ArchiveMemberOutcome::Verified),
            ("bad1".to_string(), ArchiveMemberOutcome::NoAttestation),
            (
                "bad2".to_string(),
                ArchiveMemberOutcome::Failed("sig".to_string()),
            ),
        ];
        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
        let msg = match err {
            AttestationError::Verification(m) => m,
            other => panic!("expected Verification, got {other:?}"),
        };
        assert!(msg.contains("bad1"), "missing bad1 in: {msg}");
        assert!(msg.contains("bad2"), "missing bad2 in: {msg}");
        assert!(!msg.contains("ok"), "verified member leaked into failure list: {msg}");
        assert!(msg.contains("2/3"), "expected 2/3 failure count in: {msg}");
    }

    // ==========================================================================
    // Per-file archive fallback — result → outcome mapping
    //
    // `result_to_outcome` is what translates raw `verify_attestation_blob` results into
    // the policy inputs above. A wrong mapping here silently weakens the policy —
    // e.g. mapping a real Verification error to NoAttestation would turn a hard
    // failure into a soft fall-through.
    // ==========================================================================

    #[test]
    fn result_to_outcome_maps_ok_true_to_verified() {
        assert_eq!(
            result_to_outcome(Ok(true)),
            ArchiveMemberOutcome::Verified
        );
    }

    #[test]
    fn result_to_outcome_maps_ok_false_to_failed() {
        // `Ok(false)` means the API found an attestation but sigstore-verify declined
        // to call it a success. That's a hard failure, not "no attestation" — the
        // publisher DID sign something here, and we couldn't verify it.
        match result_to_outcome(Ok(false)) {
            ArchiveMemberOutcome::Failed(msg) => {
                assert!(msg.contains("false"), "expected false-mention, got: {msg}")
            }
            other => panic!("Ok(false) must map to Failed, got {other:?}"),
        }
    }

    #[test]
    fn result_to_outcome_maps_no_attestations_to_no_attestation() {
        assert_eq!(
            result_to_outcome(Err(AttestationError::NoAttestations)),
            ArchiveMemberOutcome::NoAttestation
        );
    }

    #[test]
    fn result_to_outcome_maps_verification_error_to_failed() {
        // The fail-closed guarantee: every non-NoAttestations error becomes Failed,
        // never NoAttestation. If this regresses, an attacker who causes a verify
        // error (e.g. malformed bundle) would turn a hard failure into a soft
        // fall-through.
        let err = result_to_outcome(Err(AttestationError::Verification(
            "sigstore verification returned false".to_string(),
        )));
        assert!(matches!(err, ArchiveMemberOutcome::Failed(_)));
    }

    #[test]
    fn result_to_outcome_maps_api_error_to_failed() {
        let err = result_to_outcome(Err(AttestationError::Api("403 rate limit".to_string())));
        assert!(matches!(err, ArchiveMemberOutcome::Failed(_)));
    }

    #[test]
    fn result_to_outcome_preserves_error_message() {
        // The underlying message must survive the mapping so aggregate_* can include
        // it in the user-facing error.
        match result_to_outcome(Err(AttestationError::Api("rate limited".to_string()))) {
            ArchiveMemberOutcome::Failed(msg) => {
                assert!(msg.contains("rate limited"), "message dropped: {msg}")
            }
            other => panic!("expected Failed, got {other:?}"),
        }
    }

    // ==========================================================================
    // Per-file archive fallback — archive format detection
    // ==========================================================================

    #[test]
    fn archive_format_detects_supported_multi_file_archives() {
        use crate::file::TarFormat;
        assert_eq!(
            archive_format_for_path(Path::new("tool-1.0.tar.gz")),
            Some(TarFormat::TarGz)
        );
        assert_eq!(
            archive_format_for_path(Path::new("tool-1.0.tgz")),
            Some(TarFormat::TarGz)
        );
        assert_eq!(
            archive_format_for_path(Path::new("tool-1.0.tar")),
            Some(TarFormat::Tar)
        );
        assert_eq!(
            archive_format_for_path(Path::new("tool-1.0.zip")),
            Some(TarFormat::Zip)
        );
        assert_eq!(
            archive_format_for_path(Path::new("ext.vsix")),
            Some(TarFormat::Zip)
        );
        assert_eq!(
            archive_format_for_path(Path::new("tool.tar.zst")),
            Some(TarFormat::TarZst)
        );
    }

    #[test]
    fn archive_format_rejects_non_archive_paths() {
        // Raw binaries, single-file compressions, and unknown extensions are not
        // multi-file archives — the fallback must not attempt extraction on them.
        // Returning None here is what makes verify_attestation_via_archive_contents
        // short-circuit cleanly and surface NoAttestations to the caller.
        assert_eq!(archive_format_for_path(Path::new("tool-linux-amd64")), None);
        assert_eq!(archive_format_for_path(Path::new("tool.exe")), None);
        assert_eq!(archive_format_for_path(Path::new("binary.gz")), None);
        assert_eq!(archive_format_for_path(Path::new("binary.xz")), None);
        assert_eq!(archive_format_for_path(Path::new("file")), None);
        assert_eq!(archive_format_for_path(Path::new("")), None);
    }

    #[test]
    fn archive_format_handles_paths_with_parent_directories() {
        // File names are pulled from the final component, so download paths like
        // /tmp/mise/downloads/x.tar.gz still detect correctly.
        use crate::file::TarFormat;
        assert_eq!(
            archive_format_for_path(Path::new("/tmp/mise/downloads/x.tar.gz")),
            Some(TarFormat::TarGz)
        );
    }

    #[test]
    fn archive_format_is_case_insensitive_on_extension() {
        // TarFormat::from_file_name lowercases internally. Verify we benefit from that
        // so a .TAR.GZ download (rare but seen in the wild) still triggers fallback.
        use crate::file::TarFormat;
        assert_eq!(
            archive_format_for_path(Path::new("X.TAR.GZ")),
            Some(TarFormat::TarGz)
        );
    }

    // ==========================================================================
    // Per-file archive fallback — file enumeration
    //
    // `list_regular_files` is what stands between "the archive contains a malicious
    // symlink to /etc/passwd" and "we accidentally verified the host's shadow file".
    // The symlink-skip cases below are the security-pinned ones.
    // ==========================================================================

    fn write_regular(path: &Path, contents: &[u8]) {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent).unwrap();
        }
        std::fs::write(path, contents).unwrap();
    }

    #[test]
    fn list_regular_files_empty_dir_returns_empty() {
        let tmp = tempfile::tempdir().unwrap();
        let files = list_regular_files(tmp.path()).unwrap();
        assert!(files.is_empty(), "expected empty, got {files:?}");
    }

    #[test]
    fn list_regular_files_walks_nested_subdirectories() {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        write_regular(&root.join("top.txt"), b"a");
        write_regular(&root.join("dir/mid.bin"), b"b");
        write_regular(&root.join("dir/sub/deep.txt"), b"c");

        let files = list_regular_files(root).unwrap();
        let relative: Vec<String> = files
            .iter()
            .map(|p| p.strip_prefix(root).unwrap().display().to_string())
            .collect();
        assert_eq!(
            relative,
            vec![
                "dir/mid.bin".to_string(),
                "dir/sub/deep.txt".to_string(),
                "top.txt".to_string(),
            ],
            "all regular files in nested directories must be enumerated"
        );
    }

    #[test]
    fn list_regular_files_excludes_directories_from_result() {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("empty_dir")).unwrap();
        std::fs::create_dir_all(root.join("dir_with_file")).unwrap();
        write_regular(&root.join("dir_with_file/file"), b"x");

        let files = list_regular_files(root).unwrap();
        assert_eq!(files.len(), 1, "directories must not appear, got {files:?}");
    }

    #[test]
    fn list_regular_files_includes_hidden_files() {
        // The "every regular file" policy is strict by design. Hidden files
        // (dotfiles, .DS_Store, etc.) must be included — an attacker hiding a
        // smuggled binary as `.tool` would otherwise escape verification.
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        write_regular(&root.join(".hidden"), b"x");
        write_regular(&root.join("dir/.also_hidden"), b"y");

        let files = list_regular_files(root).unwrap();
        assert_eq!(files.len(), 2, "hidden files must be verified, got {files:?}");
    }

    #[test]
    fn list_regular_files_returns_sorted_output() {
        // Sorted output keeps error messages deterministic across platforms and
        // readdir() orderings. A test asserting "the error names bad1 before bad2"
        // should not be at the mercy of filesystem ordering.
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        write_regular(&root.join("zzz"), b"1");
        write_regular(&root.join("aaa"), b"2");
        write_regular(&root.join("mmm"), b"3");

        let files = list_regular_files(root).unwrap();
        let names: Vec<String> = files
            .iter()
            .map(|p| p.file_name().unwrap().to_string_lossy().into_owned())
            .collect();
        assert_eq!(names, vec!["aaa", "mmm", "zzz"]);
    }

    #[cfg(unix)]
    #[test]
    fn list_regular_files_skips_symlink_to_regular_file() {
        // A symlink inside the archive could point at anything — including a file the
        // publisher never signed. Skip it entirely; only regular-file bytes are
        // eligible for verification.
        use std::os::unix::fs::symlink;
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        write_regular(&root.join("target"), b"real");
        symlink("target", root.join("link")).unwrap();

        let files = list_regular_files(root).unwrap();
        let names: Vec<String> = files
            .iter()
            .map(|p| p.file_name().unwrap().to_string_lossy().into_owned())
            .collect();
        assert_eq!(names, vec!["target"], "symlink must not be listed");
    }

    #[cfg(unix)]
    #[test]
    fn list_regular_files_does_not_recurse_through_symlinked_directory() {
        // Same defense at directory granularity: a symlinked dir must not be followed,
        // or an attacker's symlink could pull arbitrary external files into the
        // verification set (or into an infinite loop).
        use std::os::unix::fs::symlink;
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        // Real directory with one file
        write_regular(&root.join("real/file_in_real"), b"a");
        // Symlink pointing at the real directory
        symlink("real", root.join("link_to_real")).unwrap();

        let files = list_regular_files(root).unwrap();
        // Should find exactly one file — not two (which would happen if we recursed
        // through both real/ and the symlink).
        assert_eq!(files.len(), 1, "symlinked dirs must not be traversed");
    }

    #[cfg(unix)]
    #[test]
    fn list_regular_files_terminates_on_symlink_loop() {
        // Defensive: if a symlink loop somehow makes it onto disk (broken extractor,
        // adversarial archive), the walk must terminate rather than spin.
        use std::os::unix::fs::symlink;
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("a")).unwrap();
        symlink("../a", root.join("a/loop")).unwrap();
        write_regular(&root.join("a/real_file"), b"x");

        // If the walk followed the symlink, this would either hang or overflow. The
        // assert just confirms it terminates and finds the one real file.
        let files = list_regular_files(root).unwrap();
        assert_eq!(files.len(), 1);
    }

    // ==========================================================================
    // Per-file archive fallback — end-to-end extraction (no network)
    //
    // These tests exercise `extract_archive_members` against real archive bytes built
    // in-memory. They stop short of `verify_attestation_blob` (which would hit the
    // GitHub API); the orchestration that wires members to that call is exercised by
    // the policy/mapping tests above.
    // ==========================================================================

    /// Build an in-memory tar.gz at `dest` containing the given (path, contents) pairs.
    /// Uses the same flate2 + tar stack as `crate::file::untar` expects to consume.
    fn build_tar_gz(
        dest: &Path,
        entries: &[(&str, &[u8])],
    ) {
        use flate2::Compression;
        use flate2::write::GzEncoder;
        use std::io::Write;
        let file = std::fs::File::create(dest).unwrap();
        let gz = GzEncoder::new(file, Compression::default());
        let mut builder = tar::Builder::new(gz);
        for (name, contents) in entries {
            let mut header = tar::Header::new_gnu();
            header.set_size(contents.len() as u64);
            header.set_mode(0o644);
            header.set_entry_type(tar::EntryType::Regular);
            header.set_cksum();
            builder
                .append_data(&mut header, *name, std::io::Cursor::new(*contents))
                .unwrap();
        }
        builder.finish().unwrap();
        builder.into_inner().unwrap().finish().unwrap();
    }

    /// Build an in-memory zip at `dest` containing the given (path, contents) pairs.
    fn build_zip(dest: &Path, entries: &[(&str, &[u8])]) {
        use std::io::Write;
        let file = std::fs::File::create(dest).unwrap();
        let mut zip = zip::ZipWriter::new(file);
        let opts = zip::write::SimpleFileOptions::default();
        for (name, contents) in entries {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(contents).unwrap();
        }
        zip.finish().unwrap();
    }

    #[test]
    fn extract_returns_not_an_archive_for_plain_binary() {
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("tool-linux-amd64");
        std::fs::write(&path, b"this is a raw binary").unwrap();

        match extract_archive_members(&path).unwrap() {
            ExtractResult::NotAnArchive => {} // expected
            ExtractResult::Extracted { .. } => {
                panic!("raw binary must not be treated as an archive")
            }
        }
    }

    #[test]
    fn extract_returns_not_an_archive_for_single_file_gzip() {
        // A `.gz` of a single binary is `TarFormat::Gz`, which `is_archive()` reports
        // as false. The fallback must skip it — there are no inner files to verify.
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("tool.gz");
        std::fs::write(&path, b"not actually gzip, but filename says so").unwrap();

        match extract_archive_members(&path).unwrap() {
            ExtractResult::NotAnArchive => {}
            ExtractResult::Extracted { .. } => panic!(".gz must not trigger per-file fallback"),
        }
    }

    #[test]
    fn extract_extracts_tar_gz_and_lists_every_regular_member() {
        let tmp = tempfile::tempdir().unwrap();
        let archive = tmp.path().join("release.tar.gz");
        build_tar_gz(
            &archive,
            &[
                ("bin/tool", b"binary"),
                ("lib/libfoo.so", b"shared"),
                ("README.md", b"docs"),
            ],
        );

        let (extracted_root, members) = match extract_archive_members(&archive).unwrap() {
            ExtractResult::Extracted { tmp, members } => (tmp.path().to_path_buf(), members),
            ExtractResult::NotAnArchive => panic!("tar.gz must extract"),
        };

        let relative: Vec<String> = members
            .iter()
            .map(|p| p.strip_prefix(&extracted_root).unwrap().display().to_string())
            .collect();
        assert_eq!(
            relative,
            vec![
                "README.md".to_string(),
                "bin/tool".to_string(),
                "lib/libfoo.so".to_string(),
            ],
            "members must be sorted and complete"
        );

        // Sanity: extraction wrote real bytes that match the archive. This proves
        // verify_attestation_blob would be called against the correct content.
        let tool_bytes = std::fs::read(extracted_root.join("bin/tool")).unwrap();
        assert_eq!(tool_bytes, b"binary");
    }

    #[test]
    fn extract_preserves_nested_layout_without_stripping() {
        // strip_components must be 0 — the publisher signed the verbatim member bytes
        // and member paths. If a future change silently strips the top dir, the
        // member digests would shift and verification would (correctly) fail; this
        // test pins the no-strip behavior so such a regression shows up here rather
        // than as a mysterious verification failure in the field.
        let tmp = tempfile::tempdir().unwrap();
        let archive = tmp.path().join("release.tar.gz");
        build_tar_gz(
            &archive,
            &[("tool-1.0/bin/tool", b"x"), ("tool-1.0/README", b"y")],
        );

        let (root, members) = match extract_archive_members(&archive).unwrap() {
            ExtractResult::Extracted { tmp, members } => (tmp.path().to_path_buf(), members),
            ExtractResult::NotAnArchive => panic!("must extract"),
        };

        let relative: Vec<String> = members
            .iter()
            .map(|p| p.strip_prefix(&root).unwrap().display().to_string())
            .collect();
        assert_eq!(
            relative,
            vec![
                "tool-1.0/README".to_string(),
                "tool-1.0/bin/tool".to_string(),
            ],
            "no stripping — top-level dir must remain in the relative path"
        );
    }

    #[test]
    fn extract_handles_zip_archives() {
        let tmp = tempfile::tempdir().unwrap();
        let archive = tmp.path().join("release.zip");
        build_zip(
            &archive,
            &[("bin/tool", b"x"), ("LICENSE", b"y")],
        );

        let members = match extract_archive_members(&archive).unwrap() {
            ExtractResult::Extracted { members, .. } => members,
            ExtractResult::NotAnArchive => panic!("zip must extract"),
        };
        assert_eq!(members.len(), 2, "zip members must be enumerated");
    }

    #[test]
    fn extract_errors_on_garbage_with_archive_extension() {
        // Defense-in-depth: if an attacker serves bytes that look like a tar.gz by
        // name but aren't, the fallback must surface a hard error rather than
        // silently skipping verification. A silent skip would let an attacker bypass
        // the fallback by shipping a corrupt archive.
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("evil.tar.gz");
        std::fs::write(&path, b"definitely not a tarball").unwrap();

        let err = extract_archive_members(&path).unwrap_err();
        assert!(
            matches!(err, AttestationError::UnsupportedFormat(_)),
            "corrupt archive must surface UnsupportedFormat, got {err:?}"
        );
        let msg = err.to_string();
        assert!(
            msg.contains("evil.tar.gz"),
            "error must name the archive, got: {msg}"
        );
    }

    #[test]
    fn extract_empty_archive_yields_empty_member_list() {
        // An archive with no regular files (only a directory entry) is degenerate.
        // The policy in `aggregate_archive_member_outcomes` would reject it as a hard
        // error if reached, but extract_archive_members itself just reports the
        // (empty) member list and lets the caller decide.
        let tmp = tempfile::tempdir().unwrap();
        let archive = tmp.path().join("empty.tar.gz");
        // Build a tar.gz whose only entry is a directory header.
        let file = std::fs::File::create(&archive).unwrap();
        let gz = flate2::write::GzEncoder::new(file, flate2::Compression::default());
        let mut builder = tar::Builder::new(gz);
        let mut header = tar::Header::new_gnu();
        header.set_size(0);
        header.set_mode(0o755);
        header.set_entry_type(tar::EntryType::Directory);
        header.set_cksum();
        builder
            .append_data(&mut header, "only_dir/", std::io::empty())
            .unwrap();
        builder.finish().unwrap();
        builder.into_inner().unwrap().finish().unwrap();

        let members = match extract_archive_members(&archive).unwrap() {
            ExtractResult::Extracted { members, .. } => members,
            ExtractResult::NotAnArchive => panic!("must extract"),
        };
        assert!(members.is_empty(), "directory-only archive has no regular files");
    }

    // ==========================================================================
    // Per-file archive fallback — display helper
    // ==========================================================================

    #[test]
    fn relative_display_name_strips_root_prefix() {
        let root = Path::new("/tmp/abc");
        let member = Path::new("/tmp/abc/dir/file");
        assert_eq!(relative_display_name(member, root), "dir/file");
    }

    #[test]
    fn relative_display_name_falls_back_when_not_under_root() {
        // Defensive: if a member somehow lives outside the temp root (shouldn't
        // happen, but file::untar is third-party code), don't panic — show the
        // absolute path so the error is still informative.
        let root = Path::new("/tmp/abc");
        let member = Path::new("/etc/passwd");
        assert_eq!(relative_display_name(member, root), "/etc/passwd");
    }
}

