+        // either they forgot (gap) or an attacker slipped `README` past them. We can't
+        // tell which, so the archive must be rejected. This is the load-bearing test
+        // for "do not guess toward permissiveness".
+        let outcomes = vec![
+            ("bin/tool".to_string(), ArchiveMemberOutcome::Verified),
+            ("README".to_string(), ArchiveMemberOutcome::NoAttestation),
+        ];
+        let err = aggregate_archive_member_outcomes(outcomes).unwrap_err();
+        match err {
+            AttestationError::Verification(msg) => {
+                assert!(
+                    msg.contains("README"),
+                    "error must name the unverified member, got: {msg}"
+                );
+                assert!(
+                    msg.contains("1/2"),
+                    "error must report the failure count, got: {msg}"
+                );
+                assert!(
+                    msg.contains("no GitHub attestation"),
+                    "error must distinguish no-attestation from failed, got: {msg}"
+                );
+            }
+            other => panic!("mixed verified/unattested must be Verification, got {other:?}"),
+        }
+    }
