+    // ==========================================================================
+    // Per-file archive fallback — end-to-end extraction (no network)
+    //
+    // These tests exercise `extract_archive_members` against real archive bytes built
+    // in-memory. They stop short of `verify_attestation_blob` (which would hit the
+    // GitHub API); the orchestration that wires members to that call is exercised by
+    // the policy/mapping tests above.
+    // ==========================================================================
+
+    /// Build an in-memory tar.gz at `dest` containing the given (path, contents) pairs.
+    /// Uses the same flate2 + tar stack as `crate::file::untar` expects to consume.
+    fn build_tar_gz(
+        dest: &Path,
+        entries: &[(&str, &[u8])],
+    ) {
+        use flate2::Compression;
+        use flate2::write::GzEncoder;
+        use std::io::Write;
+        let file = std::fs::File::create(dest).unwrap();
+        let gz = GzEncoder::new(file, Compression::default());
+        let mut builder = tar::Builder::new(gz);
+        for (name, contents) in entries {
+            let mut header = tar::Header::new_gnu();
+            header.set_size(contents.len() as u64);
+            header.set_mode(0o644);
+            header.set_entry_type(tar::EntryType::Regular);
+            header.set_cksum();
+            builder
+                .append_data(&mut header, *name, std::io::Cursor::new(*contents))
+                .unwrap();
+        }
+        builder.finish().unwrap();
+        builder.into_inner().unwrap().finish().unwrap();
+    }
+
+    /// Build an in-memory zip at `dest` containing the given (path, contents) pairs.
+    fn build_zip(dest: &Path, entries: &[(&str, &[u8])]) {
+        use std::io::Write;
+        let file = std::fs::File::create(dest).unwrap();
+        let mut zip = zip::ZipWriter::new(file);
+        let opts = zip::write::SimpleFileOptions::default();
+        for (name, contents) in entries {
+            zip.start_file(*name, opts).unwrap();
+            zip.write_all(contents).unwrap();
+        }
+        zip.finish().unwrap();
+    }
