+    #[test]
+    fn extract_empty_archive_yields_empty_member_list() {
+        // An archive with no regular files (only a directory entry) is degenerate.
+        // The policy in `aggregate_archive_member_outcomes` would reject it as a hard
+        // error if reached, but extract_archive_members itself just reports the
+        // (empty) member list and lets the caller decide.
+        let tmp = tempfile::tempdir().unwrap();
+        let archive = tmp.path().join("empty.tar.gz");
+        // Build a tar.gz whose only entry is a directory header.
+        let file = std::fs::File::create(&archive).unwrap();
+        let gz = flate2::write::GzEncoder::new(file, flate2::Compression::default());
+        let mut builder = tar::Builder::new(gz);
+        let mut header = tar::Header::new_gnu();
+        header.set_size(0);
+        header.set_mode(0o755);
+        header.set_entry_type(tar::EntryType::Directory);
+        header.set_cksum();
+        builder
+            .append_data(&mut header, "only_dir/", std::io::empty())
+            .unwrap();
+        builder.finish().unwrap();
+        builder.into_inner().unwrap().finish().unwrap();
+
+        let members = match extract_archive_members(&archive).unwrap() {
+            ExtractResult::Extracted { members, .. } => members,
